import sys
from functools import lru_cache

def solve():
    n = int(input())
    a = list(map(int, input().split()))

    @lru_cache(maxsize=None)
    def dp(l, r, last):
        # returns max moves from state (l,r) with last value = last
        if l > r:
            return 0
        res = 0
        if a[l] > last:
            res = max(res, 1 + dp(l+1, r, a[l]))
        if a[r] > last:
            res = max(res, 1 + dp(l, r-1, a[r]))
        return res

    total = dp(0, n-1, -1)
    print("Alice" if total % 2 == 1 else "Bob")

solve()

